func (this *MatrixportCore) ParseOrder(order interface{}, optionalArgs ...interface{}) interface{} {
	//
	// { "order_id": "...", "client_order_id": "...", "create_ts": ...,
	//   "status": 3, "filled_price": "...", "filled_qty": "...", "filled_cash": "..." }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id interface{} = this.SafeString(order, "order_id")
	var clientOrderId interface{} = this.SafeString(order, "client_order_id")
	var symbolId interface{} = this.SafeString(order, "symbol")
	market = this.SafeMarket(symbolId, market)
	var timestamp interface{} = this.SafeInteger(order, "create_ts")
	var sideValue interface{} = this.SafeInteger(order, "side")
	var side interface{} = nil
	if IsTrue(IsEqual(sideValue, 0)) {
		side = "buy"
	} else if IsTrue(IsEqual(sideValue, 1)) {
		side = "sell"
	}
	var statusCode interface{} = this.SafeString(order, "status")
	var status interface{} = this.ParseOrderStatus(statusCode)
	return this.SafeOrder(map[string]interface{}{
		"id":                 id,
		"clientOrderId":      clientOrderId,
		"info":               order,
		"timestamp":          timestamp,
		"datetime":           this.Iso8601(timestamp),
		"lastTradeTimestamp": nil,
		"symbol":             GetValue(market, "symbol"),
		"type":               "market",
		"timeInForce":        nil,
		"postOnly":           nil,
		"side":               side,
		"price":              this.SafeString(order, "filled_price"),
		"stopPrice":          nil,
		"triggerPrice":       nil,
		"amount":             this.SafeString2(order, "qty", "filled_qty"),
		"cost":               this.SafeString(order, "filled_cash"),
		"average":            this.SafeString(order, "filled_price"),
		"filled":             this.SafeString(order, "filled_qty"),
		"remaining":          nil,
		"status":             status,
		"fee":                nil,
		"trades":             nil,
	}, market)
}
func (this *MatrixportCore) ParseOrderStatus(status interface{}) interface{} {
	var statuses interface{} = map[string]interface{}{
		"101": "open",
		"2":   "closed",
		"3":   "closed",
		"5":   "canceled",
	}
	return this.SafeString(statuses, status, status)
}

